	ADD  R13, R5, R15
	VLD1 (R15), [V0.B16]
	ADD  R13, R3, R15
	VST1 [V0.B16], (R15)
	ADD  $0x10, R13, R13
	CMP  R10, R13
	BLO  copy_1
	ADD  R10, R5, R5
	ADD  R10, R3, R3
	ADD  R10, R6, R6

