TEXT ·sequenceDecs_decodeSync_arm64(SB), $64-32
	MOVD  br+8(FP), R3
	MOVD  24(R3), R0
	MOVBU 40(R3), R2
	MOVD  (R3), R1
	MOVD  32(R3), R3
	ADD   R3, R1, R1
	MOVD  R1, (RSP)
	MOVD  ctx+16(FP), R1
	MOVD  72(R1), R5
	MOVD  80(R1), R6
	MOVD  88(R1), R7
	MOVD  $0, R8
	MOVD  R8, 8(RSP)
	MOVD  R8, 16(RSP)
	MOVD  R8, 24(RSP)
	MOVD  112(R1), R8
	MOVD  128(R1), R9
	MOVD  R9, 32(RSP)
	MOVD  144(R1), R9
	MOVD  136(R1), R10
	MOVD  200(R1), R11
	MOVD  R11, 56(RSP)
	MOVD  176(R1), R11
	MOVD  R11, 48(RSP)
	MOVD  184(R1), R1
	MOVD  R1, 40(RSP)
	MOVD  40(RSP), R1
	MOVD  48(RSP), R16
	ADD   R1, R16, R16
	MOVD  R16, 48(RSP)

	// Calculate pointer to s.out[cap(s.out)] (a past-end pointer)
	MOVD 32(RSP), R16
	ADD  R8, R16, R16
	MOVD R16, 32(RSP)

	// outBase += outPosition
	ADD R10, R8, R8

sequenceDecs_decodeSync_bmi2_main_loop:
	MOVD (RSP), R11

	// Fill bitreader to have enough for the offset and match length.
	CMP  $0x08, R3
	BLT  sequenceDecs_decodeSync_bmi2_fill_byte_by_byte
