	LSR  $0x03, R1, R1
	SUB  R1, R11, R11
	MOVD (R11), R0
	SUB  R1, R3, R3
	AND  $0x07, R2, R2
	JMP  sequenceDecs_decodeSync_bmi2_fill_end

sequenceDecs_decodeSync_bmi2_fill_byte_by_byte:
	CMP   $0x00, R3
	BLE   sequenceDecs_decodeSync_bmi2_fill_check_overread
	CMP   $0x07, R2
	BLE   sequenceDecs_decodeSync_bmi2_fill_end
	LSL   $0x08, R0, R0
	SUB   $0x01, R11, R11
	SUB   $0x01, R3, R3
	SUB   $0x08, R2, R2
	MOVBU (R11), R1
	ORR   R1, R0, R0
	JMP   sequenceDecs_decodeSync_bmi2_fill_byte_by_byte

sequenceDecs_decodeSync_bmi2_fill_check_overread:
	CMP $0x40, R2
	BHI error_overread

sequenceDecs_decodeSync_bmi2_fill_end:
	// Update offset
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R7, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R7, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 8(RSP)

	// Update match length
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R6, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R6, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 16(RSP)

	// Fill bitreader to have enough for the remaining
	CMP  $0x08, R3
	BLT  sequenceDecs_decodeSync_bmi2_fill_2_byte_by_byte
	MOVD R2, R1
	LSR  $0x03, R1, R1
	SUB  R1, R11, R11
	MOVD (R11), R0
	SUB  R1, R3, R3
	AND  $0x07, R2, R2
	JMP  sequenceDecs_decodeSync_bmi2_fill_2_end

sequenceDecs_decodeSync_bmi2_fill_2_byte_by_byte:
	CMP   $0x00, R3
	BLE   sequenceDecs_decodeSync_bmi2_fill_2_check_overread
	CMP   $0x07, R2
	BLE   sequenceDecs_decodeSync_bmi2_fill_2_end
	LSL   $0x08, R0, R0
	SUB   $0x01, R11, R11
	SUB   $0x01, R3, R3
	SUB   $0x08, R2, R2
	MOVBU (R11), R1
	ORR   R1, R0, R0
	JMP   sequenceDecs_decodeSync_bmi2_fill_2_byte_by_byte

sequenceDecs_decodeSync_bmi2_fill_2_check_overread:
	CMP $0x40, R2
	BHI error_overread

sequenceDecs_decodeSync_bmi2_fill_2_end:
	// Update literal length
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R5, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R5, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 24(RSP)

	// Fill bitreader for state updates
	MOVD  R11, (RSP)
	MOVD  $0x00000808, R1
	UBFX  $0, R1, $8, R16
	UBFX  $8, R1, $8, R15
	LSR   R16, R7, R11
	MOVD  $1, R16
	LSL   R15, R16, R16
	SUB   $1, R16, R16
	AND   R16, R11, R11
	MOVD  ctx+16(FP), R1
	MOVD  96(R1), R16
	CMP   $0x00, R16
	BEQ   sequenceDecs_decodeSync_bmi2_skip_update
	ADD   R6, R5, R12
	ADD   R7, R12, R12
	MOVBU R12, R12
	ADD   R12, R2, R1
	MOVD  R0, R13
	MOVD  R1, R2
	NEG   R1, R16
	ROR   R16, R13, R13
	MOVD  $1, R16
	LSL   R12, R16, R16
	SUB   $1, R16, R16
	AND   R16, R13, R13

	// Update Offset State
	MOVD $1, R16
	LSL  R7, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSR  R7, R13, R13
	LSRW $0x10, R7, R7
	ADD  R1, R7, R7

	// Load ctx.ofTable
	MOVD ctx+16(FP), R1
	MOVD 48(R1), R1
	ADD  R7<<3, R1, R15
	MOVD (R15), R7

	// Update Match Length State
	MOVD $1, R16
	LSL  R6, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSR  R6, R13, R13
	LSRW $0x10, R6, R6
	ADD  R1, R6, R6

	// Load ctx.mlTable
	MOVD ctx+16(FP), R1
	MOVD 24(R1), R1
	ADD  R6<<3, R1, R15
	MOVD (R15), R6

	// Update Literal Length State
	MOVD $1, R16
	LSL  R5, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSRW $0x10, R5, R5
	ADD  R1, R5, R5

	// Load ctx.llTable
	MOVD ctx+16(FP), R1
	MOVD (R1), R1
	ADD  R5<<3, R1, R15
	MOVD (R15), R5

sequenceDecs_decodeSync_bmi2_skip_update:
	// Adjust offset
	MOVD s+0(FP), R1
	MOVD 8(RSP), R12
	CMP  $0x01, R11
	BLS  sequenceDecs_decodeSync_bmi2_adjust_offsetB_1_or_0
	ADD  $144, R1, R15
	VLD1 (R15), [V0.B16]
	MOVD R12, 144(R1)
	ADD  $152, R1, R15
	VST1 [V0.B16], (R15)
	JMP  sequenceDecs_decodeSync_bmi2_after_adjust

sequenceDecs_decodeSync_bmi2_adjust_offsetB_1_or_0:
	MOVD 24(RSP), R16
	CMP  $0x00000000, R16
	BNE  sequenceDecs_decodeSync_bmi2_adjust_offset_maybezero
	ADD  $1, R12, R12
	JMP  sequenceDecs_decodeSync_bmi2_adjust_offset_nonzero

sequenceDecs_decodeSync_bmi2_adjust_offset_maybezero:
	TST  R12, R12
	BNE  sequenceDecs_decodeSync_bmi2_adjust_offset_nonzero
	MOVD 144(R1), R12
	JMP  sequenceDecs_decodeSync_bmi2_after_adjust

sequenceDecs_decodeSync_bmi2_adjust_offset_nonzero:
	MOVD R12, R11
	MOVD $0, R13
	MOVD $-1, R14
	CMP  $0x03, R12
	CSEL EQ, R13, R11, R11
	CSEL EQ, R14, R13, R13
	ADD  R11<<3, R1, R15
	MOVD 144(R15), R16
	ADDS R16, R13, R13
	BNE  sequenceDecs_decodeSync_bmi2_adjust_temp_valid
	MOVD $0x00000001, R13

sequenceDecs_decodeSync_bmi2_adjust_temp_valid:
	CMP  $0x01, R12
	BEQ  sequenceDecs_decodeSync_bmi2_adjust_skip
	MOVD 152(R1), R11
	MOVD R11, 160(R1)

sequenceDecs_decodeSync_bmi2_adjust_skip:
	MOVD 144(R1), R11
	MOVD R11, 152(R1)
	MOVD R13, 144(R1)
	MOVD R13, R12

sequenceDecs_decodeSync_bmi2_after_adjust:
	MOVD R12, 8(RSP)

	// Check values
	MOVD 16(RSP), R1
	MOVD 24(RSP), R11
	ADD  R11, R1, R13
	MOVD s+0(FP), R14
	MOVD 256(R14), R16
	ADD  R13, R16, R16
	MOVD R16, 256(R14)
	MOVD ctx+16(FP), R13
	MOVD 104(R13), R16
	SUBS R11, R16, R16
	MOVD R16, 104(R13)
	BMI  error_not_enough_literals
	CMP  $0x00020002, R1
	BHI  sequenceDecs_decodeSync_bmi2_error_match_len_too_big
	TST  R12, R12
	BNE  sequenceDecs_decodeSync_bmi2_match_len_ofs_ok
	TST  R1, R1
	BNE  sequenceDecs_decodeSync_bmi2_error_match_len_ofs_mismatch

sequenceDecs_decodeSync_bmi2_match_len_ofs_ok:
	MOVD 24(RSP), R1
	MOVD 8(RSP), R11
	MOVD 16(RSP), R12

	// Check if we have enough space in s.out
	ADD  R12, R1, R13
	ADD  R8, R13, R13
	MOVD 32(RSP), R16
	CMP  R16, R13
	BHI  error_not_enough_space

	// Copy literals
	TST  R1, R1
	BEQ  check_offset
	MOVD $0, R13

copy_1:
	ADD  R13, R9, R15
	VLD1 (R15), [V0.B16]
	ADD  R13, R8, R15
	VST1 [V0.B16], (R15)
	ADD  $0x10, R13, R13
	CMP  R1, R13
	BLO  copy_1
	ADD  R1, R9, R9
	ADD  R1, R8, R8
	ADD  R1, R10, R10

	// Malformed input if seq.mo > t+len(hist) || seq.mo > s.windowSize)
check_offset:
	MOVD R10, R1
	MOVD 40(RSP), R16
	ADD  R16, R1, R1
	CMP  R1, R11
	BGT  error_match_off_too_big
	MOVD 56(RSP), R16
	CMP  R16, R11
	BGT  error_match_off_too_big

	// Copy match from history
	MOVD R11, R1
	SUBS R10, R1, R1
	BLS  copy_match
	MOVD 48(RSP), R13
	SUB  R1, R13, R13
	CMP  R1, R12
	BGT  copy_all_from_history
	MOVD R12, R1
	SUBS $0x10, R1, R1
	BLO  copy_4_small

copy_4_loop:
	VLD1 (R13), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R13, R13
	ADD  $0x10, R8, R8
	SUBS $0x10, R1, R1
	BHS  copy_4_loop
	ADD  R1, R13, R13
	ADD  $16, R13, R13
	ADD  R1, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R13, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_4_end

copy_4_small:
	CMP $0x03, R12
	BEQ copy_4_move_3
	CMP $0x08, R12
	BLO copy_4_move_4through7
	JMP copy_4_move_8through16

copy_4_move_3:
	MOVH (R13), R1
	MOVB 2(R13), R11
	MOVH R1, (R8)
	MOVB R11, 2(R8)
	ADD  R12, R13, R13
	ADD  R12, R8, R8
	JMP  copy_4_end

copy_4_move_4through7:
	MOVWU (R13), R1
	ADD   R12, R13, R15
	MOVWU -4(R15), R11
	MOVW  R1, (R8)
	ADD   R12, R8, R15
	MOVW  R11, -4(R15)
	ADD   R12, R13, R13
	ADD   R12, R8, R8
	JMP   copy_4_end

copy_4_move_8through16:
	MOVD (R13), R1
	ADD  R12, R13, R15
	MOVD -8(R15), R11
	MOVD R1, (R8)
	ADD  R12, R8, R15
	MOVD R11, -8(R15)
	ADD  R12, R13, R13
	ADD  R12, R8, R8

copy_4_end:
	ADD R12, R10, R10
	JMP handle_loop
	JMP loop_finished

copy_all_from_history:
	MOVD R1, R14
	SUBS $0x10, R14, R14
	BLO  copy_5_small

copy_5_loop:
	VLD1 (R13), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R13, R13
	ADD  $0x10, R8, R8
	SUBS $0x10, R14, R14
	BHS  copy_5_loop
	ADD  R14, R13, R13
	ADD  $16, R13, R13
	ADD  R14, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R13, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_5_end

copy_5_small:
	CMP $0x03, R1
	BEQ copy_5_move_3
	BLO copy_5_move_1or2
	CMP $0x08, R1
	BLO copy_5_move_4through7
	JMP copy_5_move_8through16

copy_5_move_1or2:
	MOVB (R13), R14
	ADD  R1, R13, R15
	MOVB -1(R15), R4
	MOVB R14, (R8)
	ADD  R1, R8, R15
	MOVB R4, -1(R15)
	ADD  R1, R13, R13
	ADD  R1, R8, R8
	JMP  copy_5_end

copy_5_move_3:
	MOVH (R13), R14
	MOVB 2(R13), R4
	MOVH R14, (R8)
	MOVB R4, 2(R8)
	ADD  R1, R13, R13
	ADD  R1, R8, R8
	JMP  copy_5_end

copy_5_move_4through7:
	MOVWU (R13), R14
	ADD   R1, R13, R15
	MOVWU -4(R15), R4
	MOVW  R14, (R8)
	ADD   R1, R8, R15
	MOVW  R4, -4(R15)
	ADD   R1, R13, R13
	ADD   R1, R8, R8
	JMP   copy_5_end

copy_5_move_8through16:
	MOVD (R13), R14
	ADD  R1, R13, R15
	MOVD -8(R15), R4
	MOVD R14, (R8)
	ADD  R1, R8, R15
	MOVD R4, -8(R15)
	ADD  R1, R13, R13
	ADD  R1, R8, R8

copy_5_end:
	ADD R1, R10, R10
	SUB R1, R12, R12

	// Copy match from the current buffer
copy_match:
	MOVD R8, R1
	SUB  R11, R1, R1

	// ml <= mo
	CMP R11, R12
	BHI copy_overlapping_match

	// Copy non-overlapping match
	ADD  R12, R10, R10
	MOVD R8, R11
	ADD  R12, R8, R8

copy_2:
	VLD1 (R1), [V0.B16]
	VST1 [V0.B16], (R11)
	ADD  $0x10, R1, R1
	ADD  $0x10, R11, R11
	SUBS $0x10, R12, R12
	BHI  copy_2
	JMP  handle_loop

	// Copy overlapping match
copy_overlapping_match:
	ADD R12, R10, R10

copy_slow_3:
	MOVB (R1), R11
	MOVB R11, (R8)
	ADD  $1, R1, R1
	ADD  $1, R8, R8
	SUBS $1, R12, R12
	BNE  copy_slow_3

handle_loop:
	MOVD ctx+16(FP), R1
	MOVD 96(R1), R16
	SUBS $1, R16, R16
	MOVD R16, 96(R1)
	BPL  sequenceDecs_decodeSync_bmi2_main_loop

loop_finished:
	MOVD br+8(FP), R1
	MOVD R0, 24(R1)
	MOVB R2, 40(R1)
	MOVD R3, 32(R1)

	// Update the context
	MOVD ctx+16(FP), R0
	MOVD R10, 136(R0)
	MOVD 144(R0), R1
	SUB  R1, R9, R9
	MOVD R9, 168(R0)

	// Return success
	MOVD $0x00000000, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match length error
sequenceDecs_decodeSync_bmi2_error_match_len_ofs_mismatch:
	MOVD 16(RSP), R0
	MOVD ctx+16(FP), R1
	MOVD R0, 216(R1)
	MOVD $0x00000001, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match too long error
sequenceDecs_decodeSync_bmi2_error_match_len_too_big:
	MOVD ctx+16(FP), R0
	MOVD 16(RSP), R1
	MOVD R1, 216(R0)
	MOVD $0x00000002, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match offset too long error
error_match_off_too_big:
	MOVD ctx+16(FP), R0
	MOVD 8(RSP), R1
	MOVD R1, 224(R0)
	MOVD R10, 136(R0)
	MOVD $0x00000003, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with not enough literals error
error_not_enough_literals:
	MOVD ctx+16(FP), R0
	MOVD 24(RSP), R1
	MOVD R1, 208(R0)
	MOVD $0x00000004, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with overread error
error_overread:
	MOVD $0x00000006, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with not enough output space error
error_not_enough_space:
	MOVD ctx+16(FP), R0
	MOVD 24(RSP), R1
	MOVD R1, 208(R0)
	MOVD 16(RSP), R1
	MOVD R1, 216(R0)
	MOVD R10, 136(R0)
	MOVD $0x00000005, R16
	MOVD R16, ret+24(FP)
	RET

// skipped sequenceDecs_decodeSync_safe_amd64 (BMI2 twin preferred on arm64)

// func sequenceDecs_decodeSync_safe_bmi2(s *sequenceDecs, br *bitReader, ctx *decodeSyncAsmContext) int
TEXT ·sequenceDecs_decodeSync_safe_arm64(SB), $64-32
	MOVD  br+8(FP), R3
	MOVD  24(R3), R0
	MOVBU 40(R3), R2
	MOVD  (R3), R1
	MOVD  32(R3), R3
	ADD   R3, R1, R1
	MOVD  R1, (RSP)
	MOVD  ctx+16(FP), R1
	MOVD  72(R1), R5
	MOVD  80(R1), R6
	MOVD  88(R1), R7
	MOVD  $0, R8
	MOVD  R8, 8(RSP)
	MOVD  R8, 16(RSP)
	MOVD  R8, 24(RSP)
	MOVD  112(R1), R8
	MOVD  128(R1), R9
	MOVD  R9, 32(RSP)
	MOVD  144(R1), R9
	MOVD  136(R1), R10
	MOVD  200(R1), R11
	MOVD  R11, 56(RSP)
	MOVD  176(R1), R11
	MOVD  R11, 48(RSP)
	MOVD  184(R1), R1
	MOVD  R1, 40(RSP)
	MOVD  40(RSP), R1
	MOVD  48(RSP), R16
	ADD   R1, R16, R16
	MOVD  R16, 48(RSP)

	// Calculate pointer to s.out[cap(s.out)] (a past-end pointer)
	MOVD 32(RSP), R16
	ADD  R8, R16, R16
	MOVD R16, 32(RSP)

	// outBase += outPosition
	ADD R10, R8, R8

sequenceDecs_decodeSync_safe_bmi2_main_loop:
	MOVD (RSP), R11

	// Fill bitreader to have enough for the offset and match length.
	CMP  $0x08, R3
	BLT  sequenceDecs_decodeSync_safe_bmi2_fill_byte_by_byte
	MOVD R2, R1
	LSR  $0x03, R1, R1
	SUB  R1, R11, R11
	MOVD (R11), R0
	SUB  R1, R3, R3
	AND  $0x07, R2, R2
	JMP  sequenceDecs_decodeSync_safe_bmi2_fill_end

sequenceDecs_decodeSync_safe_bmi2_fill_byte_by_byte:
	CMP   $0x00, R3
	BLE   sequenceDecs_decodeSync_safe_bmi2_fill_check_overread
	CMP   $0x07, R2
	BLE   sequenceDecs_decodeSync_safe_bmi2_fill_end
	LSL   $0x08, R0, R0
	SUB   $0x01, R11, R11
	SUB   $0x01, R3, R3
	SUB   $0x08, R2, R2
	MOVBU (R11), R1
	ORR   R1, R0, R0
	JMP   sequenceDecs_decodeSync_safe_bmi2_fill_byte_by_byte

sequenceDecs_decodeSync_safe_bmi2_fill_check_overread:
	CMP $0x40, R2
	BHI error_overread

sequenceDecs_decodeSync_safe_bmi2_fill_end:
	// Update offset
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R7, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R7, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 8(RSP)

	// Update match length
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R6, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R6, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 16(RSP)

	// Fill bitreader to have enough for the remaining
	CMP  $0x08, R3
	BLT  sequenceDecs_decodeSync_safe_bmi2_fill_2_byte_by_byte
	MOVD R2, R1
	LSR  $0x03, R1, R1
	SUB  R1, R11, R11
	MOVD (R11), R0
	SUB  R1, R3, R3
	AND  $0x07, R2, R2
	JMP  sequenceDecs_decodeSync_safe_bmi2_fill_2_end

sequenceDecs_decodeSync_safe_bmi2_fill_2_byte_by_byte:
	CMP   $0x00, R3
	BLE   sequenceDecs_decodeSync_safe_bmi2_fill_2_check_overread
	CMP   $0x07, R2
	BLE   sequenceDecs_decodeSync_safe_bmi2_fill_2_end
	LSL   $0x08, R0, R0
	SUB   $0x01, R11, R11
	SUB   $0x01, R3, R3
	SUB   $0x08, R2, R2
	MOVBU (R11), R1
	ORR   R1, R0, R0
	JMP   sequenceDecs_decodeSync_safe_bmi2_fill_2_byte_by_byte

sequenceDecs_decodeSync_safe_bmi2_fill_2_check_overread:
	CMP $0x40, R2
	BHI error_overread

sequenceDecs_decodeSync_safe_bmi2_fill_2_end:
	// Update literal length
	MOVD $0x00000808, R1
	UBFX $0, R1, $8, R16
	UBFX $8, R1, $8, R15
	LSR  R16, R5, R12
	MOVD $1, R16
	LSL  R15, R16, R16
	SUB  $1, R16, R16
	AND  R16, R12, R12
	MOVD R0, R13
	ADD  R12, R2, R1
	NEG  R1, R16
	ROR  R16, R13, R13
	MOVD $1, R16
	LSL  R12, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R13
	MOVD R1, R2
	MOVD R5, R1
	LSR  $0x20, R1, R1
	ADD  R13, R1, R1
	MOVD R1, 24(RSP)

	// Fill bitreader for state updates
	MOVD  R11, (RSP)
	MOVD  $0x00000808, R1
	UBFX  $0, R1, $8, R16
	UBFX  $8, R1, $8, R15
	LSR   R16, R7, R11
	MOVD  $1, R16
	LSL   R15, R16, R16
	SUB   $1, R16, R16
	AND   R16, R11, R11
	MOVD  ctx+16(FP), R1
	MOVD  96(R1), R16
	CMP   $0x00, R16
	BEQ   sequenceDecs_decodeSync_safe_bmi2_skip_update
	ADD   R6, R5, R12
	ADD   R7, R12, R12
	MOVBU R12, R12
	ADD   R12, R2, R1
	MOVD  R0, R13
	MOVD  R1, R2
	NEG   R1, R16
	ROR   R16, R13, R13
	MOVD  $1, R16
	LSL   R12, R16, R16
	SUB   $1, R16, R16
	AND   R16, R13, R13

	// Update Offset State
	MOVD $1, R16
	LSL  R7, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSR  R7, R13, R13
	LSRW $0x10, R7, R7
	ADD  R1, R7, R7

	// Load ctx.ofTable
	MOVD ctx+16(FP), R1
	MOVD 48(R1), R1
	ADD  R7<<3, R1, R15
	MOVD (R15), R7

	// Update Match Length State
	MOVD $1, R16
	LSL  R6, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSR  R6, R13, R13
	LSRW $0x10, R6, R6
	ADD  R1, R6, R6

	// Load ctx.mlTable
	MOVD ctx+16(FP), R1
	MOVD 24(R1), R1
	ADD  R6<<3, R1, R15
	MOVD (R15), R6

	// Update Literal Length State
	MOVD $1, R16
	LSL  R5, R16, R16
	SUB  $1, R16, R16
	AND  R16, R13, R1
	LSRW $0x10, R5, R5
	ADD  R1, R5, R5

	// Load ctx.llTable
	MOVD ctx+16(FP), R1
	MOVD (R1), R1
	ADD  R5<<3, R1, R15
	MOVD (R15), R5

sequenceDecs_decodeSync_safe_bmi2_skip_update:
	// Adjust offset
	MOVD s+0(FP), R1
	MOVD 8(RSP), R12
	CMP  $0x01, R11
	BLS  sequenceDecs_decodeSync_safe_bmi2_adjust_offsetB_1_or_0
	ADD  $144, R1, R15
	VLD1 (R15), [V0.B16]
	MOVD R12, 144(R1)
	ADD  $152, R1, R15
	VST1 [V0.B16], (R15)
	JMP  sequenceDecs_decodeSync_safe_bmi2_after_adjust

sequenceDecs_decodeSync_safe_bmi2_adjust_offsetB_1_or_0:
	MOVD 24(RSP), R16
	CMP  $0x00000000, R16
	BNE  sequenceDecs_decodeSync_safe_bmi2_adjust_offset_maybezero
	ADD  $1, R12, R12
	JMP  sequenceDecs_decodeSync_safe_bmi2_adjust_offset_nonzero

sequenceDecs_decodeSync_safe_bmi2_adjust_offset_maybezero:
	TST  R12, R12
	BNE  sequenceDecs_decodeSync_safe_bmi2_adjust_offset_nonzero
	MOVD 144(R1), R12
	JMP  sequenceDecs_decodeSync_safe_bmi2_after_adjust

sequenceDecs_decodeSync_safe_bmi2_adjust_offset_nonzero:
	MOVD R12, R11
	MOVD $0, R13
	MOVD $-1, R14
	CMP  $0x03, R12
	CSEL EQ, R13, R11, R11
	CSEL EQ, R14, R13, R13
	ADD  R11<<3, R1, R15
	MOVD 144(R15), R16
	ADDS R16, R13, R13
	BNE  sequenceDecs_decodeSync_safe_bmi2_adjust_temp_valid
	MOVD $0x00000001, R13

sequenceDecs_decodeSync_safe_bmi2_adjust_temp_valid:
	CMP  $0x01, R12
	BEQ  sequenceDecs_decodeSync_safe_bmi2_adjust_skip
	MOVD 152(R1), R11
	MOVD R11, 160(R1)

sequenceDecs_decodeSync_safe_bmi2_adjust_skip:
	MOVD 144(R1), R11
	MOVD R11, 152(R1)
	MOVD R13, 144(R1)
	MOVD R13, R12

sequenceDecs_decodeSync_safe_bmi2_after_adjust:
	MOVD R12, 8(RSP)

	// Check values
	MOVD 16(RSP), R1
	MOVD 24(RSP), R11
	ADD  R11, R1, R13
	MOVD s+0(FP), R14
	MOVD 256(R14), R16
	ADD  R13, R16, R16
	MOVD R16, 256(R14)
	MOVD ctx+16(FP), R13
	MOVD 104(R13), R16
	SUBS R11, R16, R16
	MOVD R16, 104(R13)
	BMI  error_not_enough_literals
	CMP  $0x00020002, R1
	BHI  sequenceDecs_decodeSync_safe_bmi2_error_match_len_too_big
	TST  R12, R12
	BNE  sequenceDecs_decodeSync_safe_bmi2_match_len_ofs_ok
	TST  R1, R1
	BNE  sequenceDecs_decodeSync_safe_bmi2_error_match_len_ofs_mismatch

sequenceDecs_decodeSync_safe_bmi2_match_len_ofs_ok:
	MOVD 24(RSP), R1
	MOVD 8(RSP), R11
	MOVD 16(RSP), R12

	// Check if we have enough space in s.out
	ADD  R12, R1, R13
	ADD  R8, R13, R13
	MOVD 32(RSP), R16
	CMP  R16, R13
	BHI  error_not_enough_space

	// Copy literals
	TST  R1, R1
	BEQ  check_offset
	MOVD R1, R13
	SUBS $0x10, R13, R13
	BLO  copy_1_small

copy_1_loop:
	VLD1 (R9), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R9, R9
	ADD  $0x10, R8, R8
	SUBS $0x10, R13, R13
	BHS  copy_1_loop
	ADD  R13, R9, R9
	ADD  $16, R9, R9
	ADD  R13, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R9, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_1_end

copy_1_small:
	CMP $0x03, R1
	BEQ copy_1_move_3
	BLO copy_1_move_1or2
	CMP $0x08, R1
	BLO copy_1_move_4through7
	JMP copy_1_move_8through16

copy_1_move_1or2:
	MOVB (R9), R13
	ADD  R1, R9, R15
	MOVB -1(R15), R14
	MOVB R13, (R8)
	ADD  R1, R8, R15
	MOVB R14, -1(R15)
	ADD  R1, R9, R9
	ADD  R1, R8, R8
	JMP  copy_1_end

copy_1_move_3:
	MOVH (R9), R13
	MOVB 2(R9), R14
	MOVH R13, (R8)
	MOVB R14, 2(R8)
	ADD  R1, R9, R9
	ADD  R1, R8, R8
	JMP  copy_1_end

copy_1_move_4through7:
	MOVWU (R9), R13
	ADD   R1, R9, R15
	MOVWU -4(R15), R14
	MOVW  R13, (R8)
	ADD   R1, R8, R15
	MOVW  R14, -4(R15)
	ADD   R1, R9, R9
	ADD   R1, R8, R8
	JMP   copy_1_end

copy_1_move_8through16:
	MOVD (R9), R13
	ADD  R1, R9, R15
	MOVD -8(R15), R14
	MOVD R13, (R8)
	ADD  R1, R8, R15
	MOVD R14, -8(R15)
	ADD  R1, R9, R9
	ADD  R1, R8, R8

copy_1_end:
	ADD R1, R10, R10

	// Malformed input if seq.mo > t+len(hist) || seq.mo > s.windowSize)
check_offset:
	MOVD R10, R1
	MOVD 40(RSP), R16
	ADD  R16, R1, R1
	CMP  R1, R11
	BGT  error_match_off_too_big
	MOVD 56(RSP), R16
	CMP  R16, R11
	BGT  error_match_off_too_big

	// Copy match from history
	MOVD R11, R1
	SUBS R10, R1, R1
	BLS  copy_match
	MOVD 48(RSP), R13
	SUB  R1, R13, R13
	CMP  R1, R12
	BGT  copy_all_from_history
	MOVD R12, R1
	SUBS $0x10, R1, R1
	BLO  copy_4_small

copy_4_loop:
	VLD1 (R13), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R13, R13
	ADD  $0x10, R8, R8
	SUBS $0x10, R1, R1
	BHS  copy_4_loop
	ADD  R1, R13, R13
	ADD  $16, R13, R13
	ADD  R1, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R13, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_4_end

copy_4_small:
	CMP $0x03, R12
	BEQ copy_4_move_3
	CMP $0x08, R12
	BLO copy_4_move_4through7
	JMP copy_4_move_8through16

copy_4_move_3:
	MOVH (R13), R1
	MOVB 2(R13), R11
	MOVH R1, (R8)
	MOVB R11, 2(R8)
	ADD  R12, R13, R13
	ADD  R12, R8, R8
	JMP  copy_4_end

copy_4_move_4through7:
	MOVWU (R13), R1
	ADD   R12, R13, R15
	MOVWU -4(R15), R11
	MOVW  R1, (R8)
	ADD   R12, R8, R15
	MOVW  R11, -4(R15)
	ADD   R12, R13, R13
	ADD   R12, R8, R8
	JMP   copy_4_end

copy_4_move_8through16:
	MOVD (R13), R1
	ADD  R12, R13, R15
	MOVD -8(R15), R11
	MOVD R1, (R8)
	ADD  R12, R8, R15
	MOVD R11, -8(R15)
	ADD  R12, R13, R13
	ADD  R12, R8, R8

copy_4_end:
	ADD R12, R10, R10
	JMP handle_loop
	JMP loop_finished

copy_all_from_history:
	MOVD R1, R14
	SUBS $0x10, R14, R14
	BLO  copy_5_small

copy_5_loop:
	VLD1 (R13), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R13, R13
	ADD  $0x10, R8, R8
	SUBS $0x10, R14, R14
	BHS  copy_5_loop
	ADD  R14, R13, R13
	ADD  $16, R13, R13
	ADD  R14, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R13, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_5_end

copy_5_small:
	CMP $0x03, R1
	BEQ copy_5_move_3
	BLO copy_5_move_1or2
	CMP $0x08, R1
	BLO copy_5_move_4through7
	JMP copy_5_move_8through16

copy_5_move_1or2:
	MOVB (R13), R14
	ADD  R1, R13, R15
	MOVB -1(R15), R4
	MOVB R14, (R8)
	ADD  R1, R8, R15
	MOVB R4, -1(R15)
	ADD  R1, R13, R13
	ADD  R1, R8, R8
	JMP  copy_5_end

copy_5_move_3:
	MOVH (R13), R14
	MOVB 2(R13), R4
	MOVH R14, (R8)
	MOVB R4, 2(R8)
	ADD  R1, R13, R13
	ADD  R1, R8, R8
	JMP  copy_5_end

copy_5_move_4through7:
	MOVWU (R13), R14
	ADD   R1, R13, R15
	MOVWU -4(R15), R4
	MOVW  R14, (R8)
	ADD   R1, R8, R15
	MOVW  R4, -4(R15)
	ADD   R1, R13, R13
	ADD   R1, R8, R8
	JMP   copy_5_end

copy_5_move_8through16:
	MOVD (R13), R14
	ADD  R1, R13, R15
	MOVD -8(R15), R4
	MOVD R14, (R8)
	ADD  R1, R8, R15
	MOVD R4, -8(R15)
	ADD  R1, R13, R13
	ADD  R1, R8, R8

copy_5_end:
	ADD R1, R10, R10
	SUB R1, R12, R12

	// Copy match from the current buffer
copy_match:
	MOVD R8, R1
	SUB  R11, R1, R1

	// ml <= mo
	CMP R11, R12
	BHI copy_overlapping_match

	// Copy non-overlapping match
	ADD  R12, R10, R10
	MOVD R12, R11
	SUBS $0x10, R11, R11
	BLO  copy_2_small

copy_2_loop:
	VLD1 (R1), [V0.B16]
	VST1 [V0.B16], (R8)
	ADD  $0x10, R1, R1
	ADD  $0x10, R8, R8
	SUBS $0x10, R11, R11
	BHS  copy_2_loop
	ADD  R11, R1, R1
	ADD  $16, R1, R1
	ADD  R11, R8, R8
	ADD  $16, R8, R8
	ADD  $-16, R1, R15
	VLD1 (R15), [V0.B16]
	ADD  $-16, R8, R15
	VST1 [V0.B16], (R15)
	JMP  copy_2_end

copy_2_small:
	CMP $0x03, R12
	BEQ copy_2_move_3
	BLO copy_2_move_1or2
	CMP $0x08, R12
	BLO copy_2_move_4through7
	JMP copy_2_move_8through16

copy_2_move_1or2:
	MOVB (R1), R11
	ADD  R12, R1, R15
	MOVB -1(R15), R13
	MOVB R11, (R8)
	ADD  R12, R8, R15
	MOVB R13, -1(R15)
	ADD  R12, R1, R1
	ADD  R12, R8, R8
	JMP  copy_2_end

copy_2_move_3:
	MOVH (R1), R11
	MOVB 2(R1), R13
	MOVH R11, (R8)
	MOVB R13, 2(R8)
	ADD  R12, R1, R1
	ADD  R12, R8, R8
	JMP  copy_2_end

copy_2_move_4through7:
	MOVWU (R1), R11
	ADD   R12, R1, R15
	MOVWU -4(R15), R13
	MOVW  R11, (R8)
	ADD   R12, R8, R15
	MOVW  R13, -4(R15)
	ADD   R12, R1, R1
	ADD   R12, R8, R8
	JMP   copy_2_end

copy_2_move_8through16:
	MOVD (R1), R11
	ADD  R12, R1, R15
	MOVD -8(R15), R13
	MOVD R11, (R8)
	ADD  R12, R8, R15
	MOVD R13, -8(R15)
	ADD  R12, R1, R1
	ADD  R12, R8, R8

copy_2_end:
	JMP handle_loop

	// Copy overlapping match
copy_overlapping_match:
	ADD R12, R10, R10

copy_slow_3:
	MOVB (R1), R11
	MOVB R11, (R8)
	ADD  $1, R1, R1
	ADD  $1, R8, R8
	SUBS $1, R12, R12
	BNE  copy_slow_3

handle_loop:
	MOVD ctx+16(FP), R1
	MOVD 96(R1), R16
	SUBS $1, R16, R16
	MOVD R16, 96(R1)
	BPL  sequenceDecs_decodeSync_safe_bmi2_main_loop

loop_finished:
	MOVD br+8(FP), R1
	MOVD R0, 24(R1)
	MOVB R2, 40(R1)
	MOVD R3, 32(R1)

	// Update the context
	MOVD ctx+16(FP), R0
	MOVD R10, 136(R0)
	MOVD 144(R0), R1
	SUB  R1, R9, R9
	MOVD R9, 168(R0)

	// Return success
	MOVD $0x00000000, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match length error
sequenceDecs_decodeSync_safe_bmi2_error_match_len_ofs_mismatch:
	MOVD 16(RSP), R0
	MOVD ctx+16(FP), R1
	MOVD R0, 216(R1)
	MOVD $0x00000001, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match too long error
sequenceDecs_decodeSync_safe_bmi2_error_match_len_too_big:
	MOVD ctx+16(FP), R0
	MOVD 16(RSP), R1
	MOVD R1, 216(R0)
	MOVD $0x00000002, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with match offset too long error
error_match_off_too_big:
	MOVD ctx+16(FP), R0
	MOVD 8(RSP), R1
	MOVD R1, 224(R0)
	MOVD R10, 136(R0)
	MOVD $0x00000003, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with not enough literals error
error_not_enough_literals:
	MOVD ctx+16(FP), R0
	MOVD 24(RSP), R1
	MOVD R1, 208(R0)
	MOVD $0x00000004, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with overread error
error_overread:
	MOVD $0x00000006, R16
	MOVD R16, ret+24(FP)
	RET

	// Return with not enough output space error
error_not_enough_space:
	MOVD ctx+16(FP), R0
	MOVD 24(RSP), R1
	MOVD R1, 208(R0)
	MOVD 16(RSP), R1
	MOVD R1, 216(R0)
	MOVD R10, 136(R0)
	MOVD $0x00000005, R16
	MOVD R16, ret+24(FP)
	RET
